/**
 * Real-card catalog (docs/DECISIONS.md 2026-06-12 "真實卡牌目錄").
 *
 * Text-only facts for the full zh-tw (Asia numbering) card pool, generated by
 * scripts/fetch_catalog.mjs from the TCGdex community database with image and
 * pricing fields stripped at the source. Served as a static public/ asset and
 * lazy-fetched on first picker use, so the main bundle never carries it; the
 * service worker makes it offline after one load.
 *
 * The catalog is an assist layer: user-typed card identity remains the
 * first-class path everywhere else in the app.
 */

import type { NewCardInput } from "../state/deckStore.ts";

export interface CatalogAttack {
  cost?: string[];
  name: string;
  effect?: string;
  damage?: number | string;
}

export interface CatalogAbility {
  type?: string;
  name: string;
  effect?: string;
}

export interface CatalogTypeValue {
  type: string;
  value?: string;
}

export interface CatalogCard {
  id: string;
  localId: string;
  name: string;
  category: "Pokemon" | "Trainer" | "Energy";
  stage?: string;
  suffix?: string;
  evolveFrom?: string;
  hp?: number;
  types?: string[];
  attacks?: CatalogAttack[];
  abilities?: CatalogAbility[];
  weaknesses?: CatalogTypeValue[];
  resistances?: CatalogTypeValue[];
  retreat?: number;
  /** Trainer / Energy card rule text. */
  effect?: string;
  trainerType?: string;
  energyType?: string;
  regulationMark?: string;
  /** Standard / Expanded legality (absent = false). */
  std?: boolean;
  exp?: boolean;
  rarity?: string;
  illustrator?: string;
  dexId?: number[];
  /** Pokédex flavor text. */
  description?: string;
  item?: { name: string; effect?: string };
  /** 人性化功能標籤 — deterministic keyword tags over the official card text
   *  (pipeline classify(); keys: search/draw/accel/heal/disrupt/gust/recover/
   *  protect/boost/attacker/ability). */
  fn?: string[];
  /** 熱門排名 (1 = hottest): curated seed + reprint-count proxy until the
   *  Phase 11 tournament pipeline; lower sorts first, absent sorts last. */
  pop?: number;
  set: string | null;
}

export interface CatalogSet {
  name: string;
  serie: string | null;
  date: string | null;
  official: number | null;
}

export interface Catalog {
  v: number;
  lang: string;
  source: string;
  fetchedAt: string;
  count: number;
  /** Real rotation rule the pipeline derived `std` from (official source). */
  format?: { standard: string[]; effective: string; source?: string };
  /** Newest set in the snapshot — honesty line for data freshness. */
  newest?: { id: string; name: string; date: string | null };
  sets: Record<string, CatalogSet>;
  cards: CatalogCard[];
}

// ---------------------------------------------------------------------------
// Loading — module-level promise cache; tests inject a fixture instead.

let catalogPromise: Promise<Catalog> | null = null;

export function loadCatalog(): Promise<Catalog> {
  if (catalogPromise === null) {
    catalogPromise = fetch(`${import.meta.env.BASE_URL}catalog/cards-zh-Hant.json`)
      .then((res) => {
        if (!res.ok) throw new Error(`catalog HTTP ${res.status}`);
        return res.json() as Promise<Catalog>;
      })
      .catch((err: unknown) => {
        catalogPromise = null; // allow retry after a failed load
        throw err;
      });
  }
  return catalogPromise;
}

/** Test hook: replace (or clear) the catalog without touching the network. */
export function setCatalogForTests(catalog: Catalog | null): void {
  catalogPromise = catalog === null ? null : Promise.resolve(catalog);
}

// ---------------------------------------------------------------------------
// Search

/** Case-insensitive substring search over name and set/number identity. */
export function searchCatalog(catalog: Catalog, query: string, max = 50): CatalogCard[] {
  const q = query.trim().toLowerCase();
  if (q === "") return [];
  const hits: { card: CatalogCard; rank: number }[] = [];
  for (const card of catalog.cards) {
    const name = card.name.toLowerCase();
    const idText = `${card.set ?? ""} ${card.localId} ${card.id}`.toLowerCase();
    let rank: number;
    if (name.startsWith(q)) rank = 0;
    else if (name.includes(q)) rank = 1;
    else if (idText.includes(q)) rank = 2;
    else continue;
    hits.push({ card, rank });
  }
  hits.sort((a, b) => {
    if (a.rank !== b.rank) return a.rank - b.rank;
    // 熱門排前: popular names first, then standard-legal prints, then the
    // newest set, so the playable answer lands on top.
    const pa = a.card.pop ?? Number.MAX_SAFE_INTEGER;
    const pb = b.card.pop ?? Number.MAX_SAFE_INTEGER;
    if (pa !== pb) return pa - pb;
    const aStd = a.card.std === true ? 0 : 1;
    const bStd = b.card.std === true ? 0 : 1;
    if (aStd !== bStd) return aStd - bStd;
    const da = catalog.sets[a.card.set ?? ""]?.date ?? "";
    const db = catalog.sets[b.card.set ?? ""]?.date ?? "";
    if (da !== db) return da < db ? 1 : -1;
    return a.card.id < b.card.id ? -1 : 1;
  });
  return hits.slice(0, max).map((h) => h.card);
}

// ---------------------------------------------------------------------------
// Deck mapping

/** Mulligan math counts 基礎寶可夢 only — never Basic Energy. */
export function isBasicPokemon(card: CatalogCard): boolean {
  return card.category === "Pokemon" && card.stage === "Basic";
}

export function sectionOf(card: CatalogCard): "pokemon" | "trainer" | "energy" {
  if (card.category === "Pokemon") return "pokemon";
  if (card.category === "Energy") return "energy";
  return "trainer";
}

/** A deck-row input carrying everything the catalog knows that the row stores. */
export function toNewCardInput(card: CatalogCard): NewCardInput {
  const mark =
    card.regulationMark !== undefined && /^[A-Z]$/.test(card.regulationMark)
      ? card.regulationMark
      : undefined;
  return {
    name: card.name,
    count: 1,
    isBasic: isBasicPokemon(card),
    section: sectionOf(card),
    ...(card.set !== null ? { set: card.set } : {}),
    number: card.localId,
    ...(mark !== undefined ? { mark } : {}),
    catalogId: card.id,
  };
}

/** 熱門 first, then std-legal prints, then newest set, then id — the order
 *  used by search, the builder grid and name matching. */
export function sortPrints(catalog: Catalog, cards: CatalogCard[]): CatalogCard[] {
  return [...cards].sort((a, b) => {
    const pa = a.pop ?? Number.MAX_SAFE_INTEGER;
    const pb = b.pop ?? Number.MAX_SAFE_INTEGER;
    if (pa !== pb) return pa - pb;
    const aStd = a.std === true ? 0 : 1;
    const bStd = b.std === true ? 0 : 1;
    if (aStd !== bStd) return aStd - bStd;
    const da = catalog.sets[a.set ?? ""]?.date ?? "";
    const db = catalog.sets[b.set ?? ""]?.date ?? "";
    if (da !== db) return da < db ? 1 : -1;
    return a.id < b.id ? -1 : 1;
  });
}

/** Per-catalog id → card index, built once per catalog object. */
const idIndexCache = new WeakMap<Catalog, Map<string, CatalogCard>>();
export function cardById(catalog: Catalog, id: string): CatalogCard | null {
  let index = idIndexCache.get(catalog);
  if (index === undefined) {
    index = new Map(catalog.cards.map((c) => [c.id, c]));
    idIndexCache.set(catalog, index);
  }
  return index.get(id) ?? null;
}

/**
 * Resolve a deck row to its catalog card: exact print (set+number) wins;
 * otherwise the best print of the exact (trimmed) name.
 */
export function matchRow(
  catalog: Catalog,
  row: { name: string; set?: string; number?: string },
): CatalogCard | null {
  if (row.set !== undefined && row.number !== undefined) {
    const exact = catalog.cards.find((c) => c.set === row.set && c.localId === row.number);
    if (exact) return exact;
  }
  const name = row.name.trim();
  if (name === "") return null;
  const prints = catalog.cards.filter((c) => c.name === name);
  if (prints.length === 0) return null;
  return sortPrints(catalog, prints)[0] ?? null;
}

/** The full tag patch a matched catalog card stamps onto a deck row. */
export function enrichPatch(card: CatalogCard): Omit<NewCardInput, "name" | "count"> {
  const input = toNewCardInput(card);
  return {
    isBasic: input.isBasic,
    section: input.section,
    ...(input.set !== undefined ? { set: input.set } : {}),
    ...(input.number !== undefined ? { number: input.number } : {}),
    ...(input.mark !== undefined ? { mark: input.mark } : {}),
    catalogId: input.catalogId,
  };
}

/** Kind descriptor: stage for Pokémon, trainer type, or energy type. */
export function kindOf(card: CatalogCard): { key: string | null; raw: string } {
  if (card.category === "Pokemon") {
    return card.stage !== undefined
      ? { key: stageKey(card.stage), raw: card.stage }
      : { key: "catalog.cat.pokemon", raw: "Pokemon" };
  }
  if (card.category === "Trainer") {
    return card.trainerType !== undefined
      ? { key: trainerTypeKey(card.trainerType), raw: card.trainerType }
      : { key: "catalog.cat.trainer", raw: "Trainer" };
  }
  return card.energyType !== undefined
    ? { key: energyTypeKey(card.energyType), raw: card.energyType }
    : { key: "catalog.cat.energy", raw: "Energy" };
}

