// Display key mappers — values stay data, labels go through i18n.

const STAGE_KEYS: Record<string, string> = {
  Basic: "catalog.stage.basic",
  Stage1: "catalog.stage.stage1",
  Stage2: "catalog.stage.stage2",
  VMAX: "catalog.stage.vmax",
  VSTAR: "catalog.stage.vstar",
  MEGA: "catalog.stage.mega",
  "LEVEL-UP": "catalog.stage.levelup",
  BREAK: "catalog.stage.break",
};
export function stageKey(stage: string): string | null {
  return STAGE_KEYS[stage] ?? null;
}

const TRAINER_KEYS: Record<string, string> = {
  Item: "catalog.trainer.item",
  Supporter: "catalog.trainer.supporter",
  Stadium: "catalog.trainer.stadium",
  Tool: "catalog.trainer.tool",
};
export function trainerTypeKey(trainerType: string): string | null {
  return TRAINER_KEYS[trainerType] ?? null;
}

const ENERGY_KEYS: Record<string, string> = {
  Basic: "catalog.energy.basic",
  Special: "catalog.energy.special",
  Normal: "catalog.energy.basic",
};
export function energyTypeKey(energyType: string): string | null {
  return ENERGY_KEYS[energyType] ?? null;
}

